import os
import secrets
import requests
from flask import Flask, redirect, request, session, jsonify, abort
from urllib.parse import urlencode
import jwt
from jwt import PyJWKClient
from functools import wraps

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

# OIDC Configuration - set these via environment variables
OIDC_ISSUER = os.environ.get("OIDC_ISSUER", "https://accounts.google.com")
OIDC_CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "your-client-id")
OIDC_CLIENT_SECRET = os.environ.get("OIDC_CLIENT_SECRET", "your-client-secret")
OIDC_REDIRECT_URI = os.environ.get("OIDC_REDIRECT_URI", "http://localhost:5000/callback")
OIDC_SCOPES = "openid email profile"

# Use authorization code flow instead of implicit (id_token) flow
# Authorization code flow is more secure as tokens are exchanged server-side
RESPONSE_TYPE = "code"

_oidc_config_cache = None


def get_oidc_config():
    """Fetch and cache the OIDC discovery document."""
    global _oidc_config_cache
    if _oidc_config_cache is None:
        discovery_url = f"{OIDC_ISSUER.rstrip('/')}/.well-known/openid-configuration"
        resp = requests.get(discovery_url, timeout=10)
        resp.raise_for_status()
        _oidc_config_cache = resp.json()
    return _oidc_config_cache


def validate_id_token(id_token_str):
    """
    Validate the ID token using the provider's JWKS endpoint.
    Verifies signature, issuer, audience, expiration, and nonce.
    """
    oidc_config = get_oidc_config()
    jwks_uri = oidc_config["jwks_uri"]

    jwks_client = PyJWKClient(jwks_uri)
    signing_key = jwks_client.get_signing_key_from_jwt(id_token_str)

    # Decode and validate the token
    claims = jwt.decode(
        id_token_str,
        signing_key.key,
        algorithms=["RS256", "ES256"],
        audience=OIDC_CLIENT_ID,
        issuer=OIDC_ISSUER,
        options={
            "verify_exp": True,
            "verify_iat": True,
            "verify_aud": True,
            "verify_iss": True,
            "require": ["exp", "iat", "iss", "aud", "sub", "nonce"],
        },
    )

    # Verify nonce matches what we stored in the session
    expected_nonce = session.get("oidc_nonce")
    if not expected_nonce:
        raise ValueError("No nonce found in session - possible session fixation attack")
    if not secrets.compare_digest(claims.get("nonce", ""), expected_nonce):
        raise ValueError("Nonce mismatch - possible replay attack")

    return claims


def login_required(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect("/login")
        return f(*args, **kwargs)
    return decorated_function


@app.route("/")
def index():
    """Public landing page."""
    if "user" in session:
        return jsonify({
            "message": "Welcome to the Admin Dashboard",
            "user": session["user"],
            "links": {
                "dashboard": "/dashboard",
                "logout": "/logout",
            }
        })
    return jsonify({
        "message": "Internal Admin Dashboard - Please log in",
        "links": {
            "login": "/login",
        }
    })


@app.route("/login")
def login():
    """Initiate the OIDC authorization code flow."""
    oidc_config = get_oidc_config()
    authorization_endpoint = oidc_config["authorization_endpoint"]

    # Generate a cryptographically secure state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session["oidc_state"] = state

    # Generate a cryptographically secure nonce to prevent replay attacks
    # The nonce is included in the authorization request and must be present
    # in the returned ID token, binding the token to this specific session
    nonce = secrets.token_urlsafe(32)
    session["oidc_nonce"] = nonce

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": OIDC_SCOPES,
        "response_type": RESPONSE_TYPE,
        "state": state,
        "nonce": nonce,
    }

    auth_url = f"{authorization_endpoint}?{urlencode(params)}"
    return redirect(auth_url)


@app.route("/callback")
def callback():
    """Handle the OIDC callback after user authentication."""
    # Verify state parameter to prevent CSRF attacks
    returned_state = request.args.get("state")
    expected_state = session.pop("oidc_state", None)

    if not expected_state:
        abort(400, description="Missing state in session - possible session fixation")

    if not returned_state:
        abort(400, description="Missing state parameter in callback")

    if not secrets.compare_digest(returned_state, expected_state):
        abort(400, description="State mismatch - possible CSRF attack")

    # Check for errors from the provider
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        abort(400, description=f"OIDC Error: {error} - {error_description}")

    # Authorization code flow: exchange the code for tokens server-side
    code = request.args.get("code")
    if not code:
        abort(400, description="Missing authorization code")

    # Exchange authorization code for tokens
    oidc_config = get_oidc_config()
    token_endpoint = oidc_config["token_endpoint"]

    token_response = requests.post(
        token_endpoint,
        data={
            "grant_type": "authorization_code",
            "code": code,
            "redirect_uri": OIDC_REDIRECT_URI,
            "client_id": OIDC_CLIENT_ID,
            "client_secret": OIDC_CLIENT_SECRET,
        },
        headers={"Content-Type": "application/x-www-form-urlencoded"},
        timeout=10,
    )

    if token_response.status_code != 200:
        abort(400, description="Failed to exchange authorization code for tokens")

    token_data = token_response.json()
    id_token_str = token_data.get("id_token")

    if not id_token_str:
        abort(400, description="No ID token received from provider")

    # Validate the ID token (signature, issuer, audience, expiration, nonce)
    try:
        claims = validate_id_token(id_token_str)
    except Exception as e:
        # Clean up nonce from session on failure
        session.pop("oidc_nonce", None)
        abort(400, description=f"ID token validation failed: {str(e)}")

    # Clean up the nonce after successful validation
    session.pop("oidc_nonce", None)

    # Store user info in session
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email"),
        "name": claims.get("name"),
        "email_verified": claims.get("email_verified"),
    }

    # Regenerate session to prevent session fixation
    session.modified = True

    # Redirect to the originally requested URL or dashboard
    next_url = session.pop("next_url", "/dashboard")
    return redirect(next_url)


@app.route("/dashboard")
@login_required
def dashboard():
    """Protected admin dashboard."""
    return jsonify({
        "message": "Admin Dashboard",
        "user": session["user"],
        "links": {
            "logout": "/logout",
        }
    })


@app.route("/logout")
def logout():
    """Log out the user and optionally redirect to OIDC end session endpoint."""
    session.clear()

    # Optionally redirect to the OIDC provider's logout endpoint
    try:
        oidc_config = get_oidc_config()
        end_session_endpoint = oidc_config.get("end_session_endpoint")
        if end_session_endpoint:
            params = {
                "post_logout_redirect_uri": request.host_url.rstrip("/"),
                "client_id": OIDC_CLIENT_ID,
            }
            return redirect(f"{end_session_endpoint}?{urlencode(params)}")
    except Exception:
        pass

    return jsonify({"message": "Logged out successfully"})


@app.errorhandler(400)
def bad_request(e):
    return jsonify({"error": str(e.description)}), 400


@app.errorhandler(401)
def unauthorized(e):
    return jsonify({"error": "Unauthorized"}), 401


